  }

  /* ── Back link ── */
  .pp-back {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    font-size: 0.8rem;
    font-weight: 500;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    color: var(--ink-muted);
    text-decoration: none;
    margin-bottom: 32px;
    cursor: pointer;
    transition: color var(--transition);
    background: none;
    border: none;
    padding: 0;
  }

  .pp-back:hover { color: var(--accent); }

  /* ── Project header ── */
  .pp-header {
    padding-bottom: 24px;
    border-bottom: 1.5px solid var(--border);
    margin-bottom: 36px;
  }

  .pp-header h2 {
    font-family: 'Playfair Display', serif;
    font-size: 2rem;
    font-weight: 700;
    letter-spacing: -0.02em;
    line-height: 1.15;
    color: var(--ink);
    margin-bottom: 10px;
  }

  .pp-header p {
    font-size: 0.92rem;
    color: var(--ink-muted);
