export default function ProjectPage() {
  const { id } = useParams();

  const [project, setProject] = useState(null);
  const [user, setUser] = useState(null);
  const [messages, setMessages] = useState([]);
  const [msgText, setMsgText] = useState("");

  const feedRef = useRef(null);

  useEffect(() => {
    init();
  }, [id]);

  // Auto-scroll to bottom when messages update
  useEffect(() => {
    if (feedRef.current) {
      feedRef.current.scrollTop = feedRef.current.scrollHeight;
    }
  }, [messages]);

  const init = async () => {
    const { data } = await supabase.auth.getUser();
    setUser(data.user);
    fetchProject();
    fetchMessages();
  };

  const fetchProject = async () => {
    const { data } = await supabase
      .from("projects")
      .select("*")
      .eq("id", id)
      .single();
    setProject(data);
  };

  const fetchMessages = async () => {
    const { data, error } = await supabase
      .from("project_messages")
      .select("*, profiles(name)")
      .eq("project_id", id)
      .order("created_at", { ascending: true });

    if (error) { console.log(error); return; }
    setMessages(data || []);
  };

  const sendMessage = async () => {
    if (!msgText.trim() || !user) return;

    const { error } = await supabase.from("project_messages").insert([
      { project_id: id, user_id: user.id, message: msgText },
    ]);

    if (error) { console.log(error); return; }

    setMsgText("");
    fetchMessages();
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  return (
    <>
      <style>{styles}</style>
      <div className="pp-root">
        <div className="pp-inner">

          {project ? (
            <>
              {/* Header */}
              <div className="pp-header">
                <h2>{project.title}</h2>
                {project.description && <p>{project.description}</p>}
              </div>

              {/* Community Feed */}
              <p className="section-label">Community</p>

              <div className="community-section">
                {/* Messages */}
                <div className="messages-feed" ref={feedRef}>
                  {messages.length === 0 ? (
                    <div className="feed-empty">
                      <div className="empty-icon">◻</div>
                      <p>No activity yet — be the first to post.</p>
                    </div>
                  ) : (
                    messages.map((m) => (
                      <div key={m.id} className="message-item">
                        <span className="message-author">
                          {m.profiles?.name || "User"}
                        </span>
                        <span className="message-text">{m.message}</span>
                      </div>
                    ))
                  )}
                </div>

                {/* Input bar */}
                <div className="message-input-bar">
                  <input
                    className="message-input"
                    value={msgText}
                    onChange={(e) => setMsgText(e.target.value)}
                    onKeyDown={handleKeyDown}
                    placeholder="Share an update or message…"
                  />
                  <button className="btn-post" onClick={sendMessage}>
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                      <line x1="22" y1="2" x2="11" y2="13" />
                      <polygon points="22 2 15 22 11 13 2 9 22 2" />
                    </svg>
                    Post
                  </button>
                </div>
              </div>
            </>
          ) : (
            <div className="pp-loading">Loading project…</div>
          )}

        </div>
      </div>
    </>
  );
}
